module nearest_neighbor_interpolation(
    input [7:0] address,
    input [7:0] data_in,
    output reg [7:0] data_out
);
    reg [7:0] dataArray [0:15]; // 16 elements in the data array

    always @(*) begin
        // Initialize the dataArray (for simulation purpose)
        dataArray[0] = 8'd0;
        dataArray[1] = 8'd1;
        dataArray[2] = 8'd2;
        dataArray[3] = 8'd3;
        dataArray[4] = 8'd4;
        dataArray[5] = 8'd5;
        dataArray[6] = 8'd6;
        dataArray[7] = 8'd7;
        dataArray[8] = 8'd8;
        dataArray[9] = 8'd9;
        dataArray[10] = 8'd10;
        dataArray[11] = 8'd11;
        dataArray[12] = 8'd12;
        dataArray[13] = 8'd13;
        dataArray[14] = 8'd14;
        dataArray[15] = 8'd15;

        if (address < 16) begin
            // Nearest neighbor logic
            data_out = dataArray[address];
        end else begin
            data_out = 8'd0; // Default output for out of bounds
        end
    end
endmodule
